import { IMessageComposer } from '@nitrots/nitro-renderer';

export class InspectUserStatsComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(userId: number) {
        this._data = [userId];
        console.log(
            '[Packet] InspectUserStatsComposer sent for userId:',
            userId
        );
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }

    public get disposed(): boolean {
        return this._data === null;
    }
}
